import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.DPnXhWuL.js";const h=JSON.parse('{"title":"Known Limitations","description":"","frontmatter":{"icon":"material/alert-circle-outline"},"headers":[],"relativePath":"reference/known-limitations.md","filePath":"reference/known-limitations.md","lastUpdated":1781637126000}'),n={name:"reference/known-limitations.md"};function i(s,e,c,d,u,l){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">​</a></h1><p>This page documents current constraints visible from the public source tree. Treat it as operational guidance, not a performance guarantee.</p><h2 id="source-writes-are-blocked-during-cutover" tabindex="-1">Source Writes Are Blocked During Cutover <a class="header-anchor" href="#source-writes-are-blocked-during-cutover" aria-label="Permalink to &quot;Source Writes Are Blocked During Cutover&quot;">​</a></h2><p>AOSC applies a source write block during cutover. Writes to the source fail while the block is active.</p><p>Applications must retry rejected writes. Test your retry behavior before using AOSC on important write paths.</p><p>Successful production cutovers have been observed where the application-visible write interruption was about 2 seconds to 30 seconds, including a 50 TB index at about 30 seconds. This is an observation, not an upper bound; validation, alias update, target health, cluster-manager responsiveness, shard count, document-count validation, and write load can make specific runs shorter or longer. Measure it in your environment.</p><h2 id="target-index-must-already-exist" tabindex="-1">Target Index Must Already Exist <a class="header-anchor" href="#target-index-must-already-exist" aria-label="Permalink to &quot;Target Index Must Already Exist&quot;">​</a></h2><p>AOSC validates that the target index exists before accepting a migration. It does not create the target index for you.</p><p>Create the target with the desired mappings, settings, shard count, and replica settings before calling <code>_start</code>.</p><h2 id="same-cluster-only" tabindex="-1">Same Cluster Only <a class="header-anchor" href="#same-cluster-only" aria-label="Permalink to &quot;Same Cluster Only&quot;">​</a></h2><p>AOSC migrates from source to target in the same OpenSearch cluster. Cross-cluster migrations are not supported.</p><p>For cross-cluster movement, use OpenSearch features such as remote reindex, snapshot and restore, or a separate replication pipeline, depending on your requirements.</p><h2 id="alias-based-cutover-required" tabindex="-1">Alias-Based Cutover Required <a class="header-anchor" href="#alias-based-cutover-required" aria-label="Permalink to &quot;Alias-Based Cutover Required&quot;">​</a></h2><p>AOSC swaps an alias from source to target. Applications that read or write direct concrete index names will not be moved by the alias swap.</p><h2 id="custom-routing-and-shard-count-changes-need-review" tabindex="-1">Custom Routing and Shard Count Changes Need Review <a class="header-anchor" href="#custom-routing-and-shard-count-changes-need-review" aria-label="Permalink to &quot;Custom Routing and Shard Count Changes Need Review&quot;">​</a></h2><p>AOSC preserves document IDs and routing values when indexing target documents. Replayed deletes are harder because OpenSearch <code>Translog.Delete</code> entries contain the deleted <code>_id</code> but not the routing key. The upstream feature request for recording delete routing is <a href="https://github.com/opensearch-project/OpenSearch/issues/20907" target="_blank" rel="noreferrer">OpenSearch issue 20907</a>.</p><p>This is safe in AOSC&#39;s <code>SAME_SHARD</code> and <code>SPLIT_SHARD</code> routing modes because AOSC can route the delete to the target shard or target shard group that can contain documents copied from the source shard. In <code>BULK_API</code> mode, a delete for a custom-routed document is sent without routing and OpenSearch routes it by <code>_id</code>. If the original document was routed by a different key, the delete can miss the copied target document and leave stale data.</p><p><code>BULK_API</code> mode includes shrink, non-multiple shard-count changes, and non-power-of-2 expansions. AOSC requires explicit consent through <code>accept_data_loss_if_custom_routing_is_used</code> for these topologies. The consent gate is conservative: it is based on shard topology, not a full scan proving that custom routing is present.</p><p>The highest-risk case is an application that writes the same <code>_id</code> with multiple routing keys, such as container or tenant-shard replication. In <code>BULK_API</code> topologies, target-shard collisions can cause one routed copy to overwrite another during backfill, and later unrouted deletes can miss stale target copies. This can be silent.</p><p>Review <a href="./../concepts/routing-and-replay">Routing and Replay</a> before setting <code>accept_data_loss_if_custom_routing_is_used</code>.</p><h2 id="built-in-transforms-are-1-1" tabindex="-1">Built-In Transforms Are 1:1 <a class="header-anchor" href="#built-in-transforms-are-1-1" aria-label="Permalink to &quot;Built-In Transforms Are 1:1&quot;">​</a></h2><p>The built-in <code>update</code> transform modifies <code>ctx._source</code> and emits one target document per source document. It does not currently implement public skip, split, or fan-out behavior through <code>ctx.op</code>.</p><h2 id="transform-runtime-errors-fail-the-migration" tabindex="-1">Transform Runtime Errors Fail the Migration <a class="header-anchor" href="#transform-runtime-errors-fail-the-migration" aria-label="Permalink to &quot;Transform Runtime Errors Fail the Migration&quot;">​</a></h2><p>AOSC compiles and dry-runs scripts at start, but a script can still fail on a specific document during migration. Runtime script errors fail the affected worker so the migration does not silently write incorrect data.</p><p>Write defensive scripts and test against representative data.</p><h2 id="no-general-dry-run" tabindex="-1">No General Dry Run <a class="header-anchor" href="#no-general-dry-run" aria-label="Permalink to &quot;No General Dry Run&quot;">​</a></h2><p>AOSC has dry-run behavior for some admin cleanup APIs, but it does not provide a full migration dry-run mode. Validate risky migrations in a staging or representative cluster.</p><h2 id="source-and-target-cleanup-is-manual" tabindex="-1">Source and Target Cleanup Is Manual <a class="header-anchor" href="#source-and-target-cleanup-is-manual" aria-label="Permalink to &quot;Source and Target Cleanup Is Manual&quot;">​</a></h2><p>AOSC does not delete source or target indices after completion, cancellation, or failure. Keep both until verification is complete, then delete manually according to your retention policy.</p><h2 id="metrics-export-is-not-implemented" tabindex="-1">Metrics Export Is Not Implemented <a class="header-anchor" href="#metrics-export-is-not-implemented" aria-label="Permalink to &quot;Metrics Export Is Not Implemented&quot;">​</a></h2><p>AOSC exposes progress through status APIs and logs. It does not currently export Prometheus or OpenSearch metrics.</p>',31)])])}const m=t(n,[["render",i]]);export{h as __pageData,m as default};
